#[cfg(test)]
mod e2e_table_tests {
    use glamour::{render, render_with_config, StyleConfig};
    use std::fs;
    use std::path::Path;

    fn load_fixture(name: &str) -> String {
        let path = format!("tests/conformance/fixtures/markdown/{}.md", name);
        fs::read_to_string(&path)
            .unwrap_or_else(|_| panic!("Fixture {} not found", name))
    }

    fn load_expected(name: &str) -> String {
        let path = format!("tests/conformance/fixtures/go_outputs/{}.txt", name);
        fs::read_to_string(&path)
            .unwrap_or_else(|_| panic!("Expected output {} not found", name))
    }

    #[test]
    fn test_simple_table_fixture() {
        let input = load_fixture("table_simple");
        let expected = load_expected("table_simple");

        let actual = render(&input);

        // Compare text content (ignoring ANSI differences)
        assert_text_similar(&strip_ansi(&expected), &strip_ansi(&actual));
    }

    #[test]
    fn test_complex_table_fixture() {
        let input = load_fixture("table_complex");
        let expected = load_expected("table_complex");

        let actual = render(&input);

        // Complex tables have multiple features
        verify_table_structure(&actual, &expected);
