**Parent Epic:** charmed_rust-jpq (Add Derive Macro for Model Trait)

## Objective

Implement comprehensive, user-friendly error messages for the `#[derive(Model)]` macro that provide clear diagnostics, helpful suggestions, and accurate source locations. Error messages should guide users to correct solutions.

## Detailed Requirements

### 1. Error Categories and Messages

```rust
// crates/bubbletea-macros/src/error.rs
use proc_macro2::Span;
use proc_macro_error::{Diagnostic, Level};

pub enum MacroError {
    // Structural errors
    MissingInitMethod { span: Span, struct_name: String },
    MissingUpdateMethod { span: Span, struct_name: String },
    MissingViewMethod { span: Span, struct_name: String },
    DuplicateAttribute { span: Span, attr_name: String, first_span: Span },

    // Signature errors
    InitWrongSignature { span: Span, expected: String, found: String },
    UpdateWrongSignature { span: Span, expected: String, found: String },
    ViewWrongSignature { span: Span, expected: String, found: String },

    // State attribute errors
    StateFieldNotClone { span: Span, field_name: String, type_name: String },
    StateFieldNotPartialEq { span: Span, field_name: String },
    InvalidEqFunction { span: Span, fn_name: String },

    // Type errors
    UnknownMessageType { span: Span, suggested: Vec<String> },
    GenericBoundsMissing { span: Span, param: String, bounds: Vec<String> },

    // Usage errors
    NotAStruct { span: Span, found: String },
    UnnamedFields { span: Span },
    InvalidAttribute { span: Span, attr: String, valid: Vec<String> },
}

impl MacroError {
    pub fn to_diagnostic(&self) -> Diagnostic {
        match self {
            MacroError::MissingInitMethod { span, struct_name } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    format!("struct `{}` is missing an #[init] method", struct_name)
                )
                .help("Add a method annotated with #[init] that returns (Self, Command<Msg>)")
                .note("Example:\n\n    #[init]\n    fn init() -> (Self, Command<Msg>) {\n        (Self::default(), Command::none())\n    }")
            }

            MacroError::MissingUpdateMethod { span, struct_name } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    format!("struct `{}` is missing an #[update] method", struct_name)
                )
                .help("Add a method annotated with #[update] that handles messages")
                .note("Example:\n\n    #[update]\n    fn update(&mut self, msg: Msg) -> Command<Msg> {\n        match msg {\n            Msg::Tick => { /* handle tick */ }\n        }\n        Command::none()\n    }")
            }

            MacroError::DuplicateAttribute { span, attr_name, first_span } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    format!("duplicate #[{}] attribute", attr_name)
                )
                .span_note(*first_span, "first attribute here")
                .help(format!("Remove one of the #[{}] attributes; only one is allowed per struct", attr_name))
            }

            MacroError::InitWrongSignature { span, expected, found } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    "incorrect signature for #[init] method"
                )
                .help(format!("Expected: {}", expected))
                .note(format!("Found: {}", found))
            }

            MacroError::StateFieldNotClone { span, field_name, type_name } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    format!("state field `{}` of type `{}` does not implement Clone", field_name, type_name)
                )
                .help("State fields require Clone for change detection snapshots")
                .note("Options:\n  1. Derive Clone on the field type\n  2. Use #[state(skip)] to exclude this field\n  3. Wrap in Rc<T> and use #[state(eq = \"rc_ptr_eq\")]")
            }

            MacroError::NotAStruct { span, found } => {
                Diagnostic::spanned(
                    *span,
                    Level::Error,
                    format!("#[derive(Model)] can only be used on structs, found {}", found)
                )
                .help("Model must be derived on a struct with named fields")
            }

            // ... more variants
            _ => todo!("Implement diagnostic for {:?}", self)
        }
    }
}
```

### 2. Error Emission Utilities

```rust
// crates/bubbletea-macros/src/error.rs
use proc_macro_error::{abort, emit_error, emit_warning};

/// Emit error and continue (for collecting multiple errors)
pub fn emit(error: MacroError) {
    error.to_diagnostic().emit();
}

/// Emit error and abort immediately
pub fn abort_with(error: MacroError) -> ! {
    error.to_diagnostic().abort()
}

/// Accumulate multiple errors before aborting
pub struct ErrorAccumulator {
    errors: Vec<MacroError>,
}

impl ErrorAccumulator {
    pub fn new() -> Self {
        Self { errors: Vec::new() }
    }

    pub fn push(&mut self, error: MacroError) {
        self.errors.push(error);
    }

    pub fn is_empty(&self) -> bool {
        self.errors.is_empty()
    }

    /// Emit all errors and abort if any exist
    pub fn finish(self) {
        if self.errors.is_empty() {
            return;
        }

        for error in &self.errors[..self.errors.len()-1] {
            emit(error.clone());
        }

        // Abort on the last error
        if let Some(last) = self.errors.into_iter().last() {
            abort_with(last);
        }
    }
}
```

### 3. Contextual Suggestions

```rust
// crates/bubbletea-macros/src/error.rs

/// Generate suggestions based on what was found
pub fn suggest_fix(context: &ParseContext) -> Vec<String> {
    let mut suggestions = Vec::new();

    // Check for common typos
    if context.has_method("init") && !context.has_attr("init") {
        suggestions.push(
            "Found method named 'init' without #[init] attribute. Did you forget to add #[init]?".into()
        );
    }

    // Check for similar method names
    if !context.has_method("update") && context.has_method("on_update") {
        suggestions.push(
            "Found 'on_update' method. Rename to 'update' and add #[update] attribute.".into()
        );
    }

    // Check for async methods
    if context.has_async_update() {
        suggestions.push(
            "#[update] methods should not be async. Use Command::perform() for async operations.".into()
        );
    }

    suggestions
}
