```rust
pub struct Pager {
    viewport: Viewport,
    content: RenderedContent,
    status: StatusBar,
    mode: PagerMode,
}

impl Pager {
    pub fn new(content: RenderedContent, config: PagerConfig) -> Self {
        let viewport = Viewport::new(config.width, config.height);
        // Initialize pager state
    }

    pub fn scroll_down(&mut self, lines: usize) {
        self.viewport.scroll_down(lines);
    }

    pub fn scroll_to_percent(&mut self, percent: f32) {
        let line = (self.content.total_lines() as f32 * percent) as usize;
        self.viewport.scroll_to(line);
    }
}

pub struct Viewport {
    offset: usize,
    height: usize,
    width: usize,
}
