    fn test_canonical_language_names() {
        let detector = LanguageDetector::new();

        assert_eq!(detector.detect("rust").name, "Rust");
        assert_eq!(detector.detect("python").name, "Python");
        assert_eq!(detector.detect("javascript").name, "JavaScript");
        assert_eq!(detector.detect("go").name, "Go");
    }

    #[test]
    fn test_common_aliases() {
        let detector = LanguageDetector::new();

        assert_eq!(detector.detect("rs").name, "Rust");
        assert_eq!(detector.detect("py").name, "Python");
        assert_eq!(detector.detect("js").name, "JavaScript");
        assert_eq!(detector.detect("ts").name, "TypeScript");
        assert_eq!(detector.detect("sh").name, "Bash");
        assert_eq!(detector.detect("bash").name, "Bash");
        assert_eq!(detector.detect("yml").name, "YAML");
    }

    #[test]
    fn test_case_insensitivity() {
        let detector = LanguageDetector::new();

        assert_eq!(detector.detect("RUST").name, detector.detect("rust").name);
        assert_eq!(detector.detect("Python").name, detector.detect("python").name);
        assert_eq!(detector.detect("JavaScript").name, detector.detect("javascript").name);
    }

    #[test]
