 {"id":"charmed_rust-bf2t","title":"Implement Middleware Chain Execution","description":"# Implement Middleware Chain Execution

## Objective
Create a middleware framework that allows composable request processing for SSH connections, similar to HTTP middleware patterns.

## Implementation Details

### Middleware Trait
```rust
use async_trait::async_trait;

/// Context passed through middleware chain
pub struct Context {
    pub session: Arc<Mutex<TerminalSession>>,
    pub user: AuthenticatedUser,
    pub remote_addr: SocketAddr,
    pub channel: ChannelId,
    pub extensions: Extensions,
}

impl Context {
    /// Get typed extension data
    pub fn get<T: Send + Sync + 'static>(&self) -> Option<&T> {
        self.extensions.get::<T>()
    }

    /// Set typed extension data
    pub fn set<T: Send + Sync + 'static>(&mut self, value: T) {
        self.extensions.insert(value);
    }
}

/// Middleware trait for processing SSH sessions
#[async_trait]
pub trait Middleware: Send + Sync + 'static {
    /// Process the request, optionally calling next middleware
    async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError>;

    /// Optional: Name for logging/debugging
    fn name(&self) -> &str {
        std::any::type_name::<Self>()
    }
}

/// Represents the next middleware in the chain
pub struct Next<'a> {
    middleware: &'a [Arc<dyn Middleware>],
    handler: &'a dyn Handler,
}

impl<'a> Next<'a> {
    pub async fn run(self, ctx: &mut Context) -> Result<(), WishError> {
        if let Some((current, rest)) = self.middleware.split_first() {
            let next = Next { middleware: rest, handler: self.handler };
            current.handle(ctx, next).await
        } else {
            // End of chain, run the handler
            self.handler.handle(ctx).await
        }
    }
}
```

### Built-in Middleware
```rust
/// Logging middleware
pub struct LoggingMiddleware {
    level: log::Level,
}

#[async_trait]
impl Middleware for LoggingMiddleware {
    async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError> {
        let start = Instant::now();
        log::log!(self.level, "Session started: user={} addr={}", 
                  ctx.user.username, ctx.remote_addr);

        let result = next.run(ctx).await;

        let duration = start.elapsed();
        match &result {
            Ok(_) => log::log!(self.level, "Session ended: user={} duration={:?}", 
                              ctx.user.username, duration),
            Err(e) => log::error!("Session error: user={} error={}", 
                                  ctx.user.username, e),
        }
        result
    }
}

/// Rate limiting middleware
pub struct RateLimitMiddleware {
    limiter: Arc<RateLimiter>,
}

#[async_trait]
impl Middleware for RateLimitMiddleware {
    async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError> {
        if !self.limiter.check(&ctx.remote_addr) {
            log::warn!("Rate limit exceeded for {}", ctx.remote_addr);
            return Err(WishError::RateLimited);
        }
        next.run(ctx).await
    }
}

/// Access control middleware
pub struct AccessControlMiddleware {
    allowed_users: HashSet<String>,
}

#[async_trait]
impl Middleware for AccessControlMiddleware {
    async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError> {
        if !self.allowed_users.contains(&ctx.user.username) {
            log::info!("Access denied for user '{}'", ctx.user.username);
            return Err(WishError::AccessDenied);
        }
        next.run(ctx).await
    }
}

/// Banner/MOTD middleware
pub struct BannerMiddleware {
    banner: String,
}

#[async_trait]
impl Middleware for BannerMiddleware {
    async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError> {
        // Send banner before proceeding
        ctx.session.lock().await.write(self.banner.as_bytes())?;
        log::debug!("Banner sent to {}", ctx.user.username);
        next.run(ctx).await
    }
}
```

### Middleware Chain Builder
```rust
pub struct MiddlewareChain {
    middleware: Vec<Arc<dyn Middleware>>,
}

impl MiddlewareChain {
    pub fn new() -> Self {
        Self { middleware: Vec::new() }
    }

    pub fn use_middleware<M: Middleware>(mut self, middleware: M) -> Self {
        log::debug!("Adding middleware: {}", middleware.name());
        self.middleware.push(Arc::new(middleware));
        self
    }

    pub async fn execute(&self, ctx: &mut Context, handler: &dyn Handler) -> Result<(), WishError> {
        log::debug!("Executing middleware chain ({} middleware)", self.middleware.len());
        let next = Next {
            middleware: &self.middleware,
            handler,
        };
        next.run(ctx).await
    }
}

